import Visibility from "@mui/icons-material/Visibility";
import VisibilityOff from "@mui/icons-material/VisibilityOff";
import { Box, Button, TextField } from "@mui/material";
import IconButton from "@mui/material/IconButton";
import InputAdornment from "@mui/material/InputAdornment";
import Link from "@mui/material/Link";
import Typography from "@mui/material/Typography";
import React, { useEffect, useState } from "react";
import shruti_logo from "../../images/Shruti_logo.png";
import ResetPasswordOTP from "./ResetPasswordOTP";

function NewSignIn({ setShow, setUserName, setSnackbar }) {
  const [openPassWordReset, setOpenPassWordReset] = useState(false);
  const [userInfo, setUserInfo] = useState({
    username: "",
    password: "",
  });
  const [showPassword, setShowPassword] = useState(false);

  useEffect(() => {
    // loadCaptchaEnginge(6, "black", "white");
    // document.getElementById("user_captcha_input").click();
  }, []);

  const checkCaptcha = () => {
    return true;
    // let user_captcha = document.getElementById("user_captcha_input").value;
    // if (validateCaptcha(user_captcha) === true) {
    //   loadCaptchaEnginge(6, "black", "white");
    //   document.getElementById("user_captcha_input").value = "";
    //   return true;
    // } else {
    //   document.getElementById("user_captcha_input").value = "";
    //   return false;
    // }
  };
  const handleModalClose = () => {
    setOpenPassWordReset(false);
  };
  const handleChange = (e) => {
    setUserInfo((prevState) => ({
      ...prevState,
      [e.target.name]: e.target.value,
    }));
  };
  const handleSubmit = async () => {
    if (checkCaptcha()) {
      if (userInfo["username"] !== "" && userInfo["password"] !== "") {
        var myHeaders = new Headers();
        myHeaders.append("Content-Type", "application/json");
        var raw = JSON.stringify({
          username: userInfo["username"],
          password: userInfo["password"],
          module: "authentication",
          submodule: "sign_in",
        });

        var requestOptions = {
          method: "POST",
          headers: myHeaders,
          body: raw,
          redirect: "follow",
        };

        fetch(process.env.REACT_APP_BASE_URL, requestOptions)
          .then((response) => {
            return response.json();
          })
          .then((result) => {
            if (result["status"] === 200) {
              setSnackbar({
                type: "success",
                content: result["message"],
                show: true,
              });
              localStorage.setItem("username", userInfo["username"]);
              setShow("");
              setUserName(userInfo["username"]);
            } else {
              setSnackbar({
                type: "error",
                content: result["message"],
                show: true,
              });
            }
          })
          .catch((error) => {
            setSnackbar({
              type: "error",
              content: "Something went wrong,please try again.",
              show: true,
            });
          });
      } else {
        setSnackbar({
          type: "error",
          content: "ইমেইল অথবা পাসওয়ার্ড ঘরটি খালি আছে",
          show: true,
        });
      }
    } else {
      setSnackbar({
        type: "error",
        content: "Wrong Captcha",
        show: true,
      });
    }
  };
  return (
    <Box
      id="kicka-kicka"
      sx={{
        display: "flex",
        flexDirection: "column",
        gap: 2,
        justifyContent: "center",
        alignItems: "center",
        border: "0px solid red",
        mx: "auto",
        height: "100%",
        width: "100%",
        overflowY: "auto",
      }}
    >
      <Box
        sx={{
          display: "flex",
          // flexDirection: "column",
          // gap: 2,
          justifyContent: "center",
          alignItems: "center",
          border: "0px solid red",
          // mx: "auto",
          height: "25%",
          width: "100%",
          overflowY: "auto",
        }}
      >
        <Box
          sx={{
            height: "50%",
            border: "0px solid green",
            width: "100%",
            display: "flex",
            justifyContent: "center",
            alignItems: "center",
            flexDirection: "column",
          }}
        >
          <img
            src={shruti_logo}
            alt="main_logo"
            style={{ height: "75%", width: "auto" }}
          />
          <Typography
            sx={{
              fontFamily: "'Noto Serif Bengali', serif",
              fontSize: { xs: "175%", sm: "175%", md: "150%", lg: "150%" },
              fontWeight: "bold",
              color: "#808285",
            }}
          >
            উচ্চারণ
          </Typography>
        </Box>
      </Box>

      <Box
        sx={{
          height: "10%",
          border: "0px solid green",
          width: "100%",
          display: "flex",
          justifyContent: "center",
          alignItems: "center",
        }}
      >
        <span
          style={{
            fontSize: "150%",
            fontFamily: "'Noto Serif Bengali', serif",
          }}
        >
          প্রবেশ করুন
        </span>
      </Box>
      <Box
        sx={{
          height: "60%",
          border: "0px solid orange",
          width: "80%",
        }}
      >
        <TextField
          fullWidth
          id="username_textfield"
          variant="outlined"
          margin="normal"
          label="ইমেইল"
          value={userInfo.username}
          onChange={handleChange}
          name="username"
          size="small"
          InputLabelProps={{
            sx: {
              fontFamily: "'Noto Serif Bengali', serif",
              fontWeight: "bold",
              fontSize: "19px",
              color: "#949599",
            },
            shrink: true,
          }}
        />
        <TextField
          // {...params}
          fullWidth
          variant="outlined"
          margin="normal"
          id="password_textfield"
          label="পাসওয়ার্ড"
          type={showPassword ? "text" : "password"}
          value={userInfo.password}
          onChange={handleChange}
          name="password"
          size="small"
          InputProps={{
            endAdornment: (
              <InputAdornment position="end">
                <IconButton
                  onClick={() => setShowPassword(!showPassword)}
                  edge="end"
                >
                  {showPassword ? <Visibility /> : <VisibilityOff />}
                </IconButton>
              </InputAdornment>
            ),
          }}
          InputLabelProps={{
            sx: {
              fontFamily: "'Noto Serif Bengali', serif",
              fontWeight: "bold",
              fontSize: "18px",
              color: "#949599",
              // "&.MuiOutlinedInput-notchedOutline": { fontSize: "18px" }
            },
            shrink: true,
          }}
        />
        {/* <Box
          sx={{
            border: "0px solid #EFEFEF",
            display: "flex",
            justifyContent: "center",
            flexDirection: "column",
            borderRadius: "5px",
          }}
        >
          <LoadCanvasTemplate reloadColor="red" reloadText="Reload" />
          <TextField
            margin="normal"
            id="user_captcha_input"
            label="Captcha"
            size="small"
          />
        </Box> */}
        <Box
          sx={{
            display: "flex",
            flexDirection: "row",
            justifyContent: "space-between",
            paddingTop: "20px",
          }}
        >
          <Button
            color="error"
            variant="transparent"
            fullWidth
            onClick={() => setShow("sign-up")}
            sx={{
              width: "40%",
              border: "1px solid #cccccc",
              "&:hover": {
                backgroundColor: "inherit", // You can set this to 'none' or any other value to remove the hover effect
              },
              fontFamily: "'Noto Serif Bengali', serif",
              fontWeight: "bold",
              color: "#666666",
            }}
          >
            রেজিস্টার
          </Button>
          <Button
            color="success"
            variant="transparent"
            fullWidth
            onClick={() => handleSubmit()}
            sx={{
              width: "40%",
              border: "1px solid #cccccc",
              "&:hover": {
                backgroundColor: "inherit", // You can set this to 'none' or any other value to remove the hover effect
              },
              fontFamily: "'Noto Serif Bengali', serif",
              fontWeight: "bold",
              color: "#666666",
            }}
          >
            লগইন
          </Button>
        </Box>
        <Box
          sx={{
            width: "100%",
            display: "flex",
            flexDirection: "row",
            justifyContent: "flex-end",
            marginTop: 2,
          }}
        >
          <Link
            href="#"
            variant="body2"
            onClick={() => setOpenPassWordReset(true)}
          >
            পাসওয়ার্ড ভুলে গেছেন?
          </Link>
        </Box>
      </Box>
      {openPassWordReset ? (
        <ResetPasswordOTP
          handleModalClose={handleModalClose}
          setSnackbar={setSnackbar}
        />
      ) : null}
    </Box>
  );
}

export default NewSignIn;
