import AutorenewIcon from "@mui/icons-material/Autorenew";
import CloseIcon from "@mui/icons-material/Close";
import { Box, TextField, Typography } from "@mui/material";
import Button from "@mui/material/Button";
import Dialog from "@mui/material/Dialog";
import Slide from "@mui/material/Slide";
import React, { useEffect, useState } from "react";

const OTPTIME_LIMIT = 900;

const Transition = React.forwardRef(function Transition(props, ref) {
  return <Slide direction="up" ref={ref} {...props} />;
});

function OTPModal({ setShowOTPModal, userInfo, setSnackbar, setShow }) {
  const [otp, setOtp] = useState("");

  const [seconds, setSeconds] = useState(0);
  useEffect(() => {
    let timerId;

    timerId = setInterval(() => {
      setSeconds((seconds) => seconds + 1);
    }, 1000);

    return () => clearInterval(timerId);
  }, [seconds]);
  const formatTime = (totalSeconds) => {
    var minutes = Math.floor(totalSeconds / 60);
    var seconds = totalSeconds % 60;
    var formattedTime = minutes + ":" + (seconds < 10 ? "0" : "") + seconds;
    return formattedTime;
  };

  const Registration = () => {
    var myHeaders = new Headers();
    myHeaders.append("Content-Type", "application/json");
    var raw = JSON.stringify({
      username: userInfo["username"],
      password: userInfo["password"],
      module: "authentication",
      submodule: "sign_up",
    });

    var requestOptions = {
      method: "POST",
      headers: myHeaders,
      body: raw,
      redirect: "follow",
    };

    fetch(process.env.REACT_APP_BASE_URL, requestOptions)
      .then((response) => {
        return response.json();
      })
      .then((result) => {
        if (result["status"] === 200) {
          setSnackbar({
            type: "success",
            content: result["message"],
            show: true,
          });
        } else {
          setSnackbar({
            type: "error",
            content: result["message"],
            show: true,
          });
        }
        setShow("sign-in");
        setShowOTPModal(false);
      })
      .catch((error) => {
        setShowOTPModal(false);
      });
  };
  const handleOTPSubmit = () => {
    var myHeaders = new Headers();
    myHeaders.append("Content-Type", "application/json");

    var raw = JSON.stringify({
      username: userInfo["username"],
      otp: otp,
      module: "authentication",
      submodule: "otp_validation",
    });

    var requestOptions = {
      method: "POST",
      headers: myHeaders,
      body: raw,
      redirect: "follow",
    };

    fetch(process.env.REACT_APP_BASE_URL, requestOptions)
      .then((response) => response.json())
      .then((result) => {
        if (result["status"] === 200) {
          setSnackbar({
            type: "success",
            content: result["message"],
            show: true,
          });
          Registration();
        } else {
          setSnackbar({
            type: "error",
            content: result["message"],
            show: true,
          });
        }
      })
      .catch((error) => {
        setSnackbar({
          type: "error",
          content: "Something went wrong, please try again.",
          show: true,
        });
      });
  };
  const handleOTPInput = (event) => {
    setOtp(event.target.value);
  };
  const handleResendOTP = () => {
    setSeconds(0);
    handleOTPSubmit();
  };
  return (
    <Dialog
      open={true}
      TransitionComponent={Transition}
      keepMounted
      aria-describedby="alert-dialog-slide-description"
    >
      <Box
        sx={{
          display: "flex",
          justifyContent: "flex-end",
          border: "0px solid red",
          width: "100%",
          mx: "auto",
        }}
      >
        <CloseIcon
          fontSize="large"
          sx={{
            cursor: "pointer",
            p: 1,
          }}
          onClick={() => {
            setShowOTPModal(false);
          }}
        />
      </Box>

      <Box
        sx={{
          margin: "50px",
          display: "flex",
          flexDirection: "column",
          justifyContent: "center",
          alignContent: "center",
          gap: 3,
        }}
      >
        <Typography
          sx={{ textAlign: "center", fontSize: "1.2rem", fontWeight: 600 }}
        >
          আপনার ইমেইলে একটি গোপন কোড পাঠানো হয়েছে, সেই গোপন কোডটি এখানে লিখুন
        </Typography>

        <TextField
          required
          fullWidth
          label="OTP"
          id="confirmPassword"
          autoComplete="new-password"
          onChange={handleOTPInput}
        />
        <Box
          sx={{
            display: "flex",
            width: "100%",
            justifyContent: "space-between",
          }}
        >
          <Typography color="initial">
            {OTPTIME_LIMIT - seconds === 0
              ? setShowOTPModal(false)
              : formatTime(OTPTIME_LIMIT - seconds)}
          </Typography>
          <Box
            onClick={handleResendOTP}
            sx={{
              display: "flex",
              flexDirection: "column",
              justifyContent: "center",
              alignItems: "center",
              cursor: "pointer",
            }}
          >
            <AutorenewIcon />
            <Typography>resend</Typography>
          </Box>
        </Box>

        <Button variant="contained" onClick={handleOTPSubmit}>
          Submit
        </Button>
      </Box>
    </Dialog>
  );
}

export default OTPModal;
