import CloseIcon from "@mui/icons-material/Close";
import LockIcon from "@mui/icons-material/Lock";
import { Box, Button, TextField, Typography } from "@mui/material";
import Backdrop from "@mui/material/Backdrop";
import CircularProgress from "@mui/material/CircularProgress";
import Dialog from "@mui/material/Dialog";
import DialogContent from "@mui/material/DialogContent";
import IconButton from "@mui/material/IconButton";
import React, { useEffect, useState } from "react";

function ResetPasswordOTP({ handleModalClose, setSnackbar }) {
  const [open, setOpen] = useState(true);
  const [username, setUsername] = useState("");
  const [currentStage, setCurrentStage] = useState("sendEmail");
  const [OTP, setOTP] = useState("");
  const [passWord, setPassWord] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [showResetButton, setShowResetButton] = useState(false);
  const [showbackDrop, setShowbackDrop] = useState(false);
  useEffect(() => {
    if (
      passWord !== "" &&
      confirmPassword !== "" &&
      passWord === confirmPassword
    ) {
      setShowResetButton(true);
    }
  }, [passWord, confirmPassword]);

  const handleClose = () => {
    setOpen(false);
    handleModalClose();
  };
  const handleChange = (e) => {
    setUsername(e.target.value);
  };
  const handleEmailSubmit = () => {
    setShowbackDrop(true);
    var myHeaders = new Headers();
    myHeaders.append("Content-Type", "application/json");

    var raw = JSON.stringify({
      is_reset: true,
      username: username,
      module: "authentication",
      submodule: "send_mail",
    });

    var requestOptions = {
      method: "POST",
      headers: myHeaders,
      body: raw,
      redirect: "follow",
    };

    fetch(process.env.REACT_APP_BASE_URL, requestOptions)
      .then((response) => response.json())
      .then((result) => {
        setShowbackDrop(false);
        if (result.status === 400 || result.status === 500) {
          setSnackbar({
            type: "error",
            content: result.message,
            show: true,
          });
        } else {
          setCurrentStage("sendOTP");
        }
      })
      .catch((error) => {
        setShowbackDrop(false);
        setSnackbar({
          type: "error",
          content: "SomeThing Went Wrong. Please Try Again",
          show: true,
        });
      });
  };
  const handleOTPInput = (e) => {
    setOTP(e.target.value);
  };
  const handleOTPSubmit = () => {
    setShowbackDrop(true);
    var myHeaders = new Headers();
    myHeaders.append("Content-Type", "application/json");

    var raw = JSON.stringify({
      username: username,
      otp: OTP,
      module: "authentication",
      submodule: "otp_validation",
    });

    var requestOptions = {
      method: "POST",
      headers: myHeaders,
      body: raw,
      redirect: "follow",
    };

    fetch(process.env.REACT_APP_BASE_URL, requestOptions)
      .then((response) => response.json())
      .then((result) => {
        setShowbackDrop(false);
        if (result["status"] === 200) {
          setSnackbar({
            type: "success",
            content: result["message"],
            show: true,
          });
          setCurrentStage("resetpassword");
        } else {
          setSnackbar({
            type: "error",
            content: result["message"],
            show: true,
          });
        }
      })
      .catch((error) => {
        setShowbackDrop(false);
        setSnackbar({
          type: "error",
          content: "Something went wrong, please try again.",
          show: true,
        });
      });
  };
  const handlePassWordChange = (e) => {
    setPassWord(e.target.value);
  };
  const hadleConfirmPassWordChange = (e) => {
    setConfirmPassword(e.target.value);
  };
  const handlePassResetSubmit = () => {
    setShowbackDrop(true);
    var myHeaders = new Headers();
    myHeaders.append("Content-Type", "application/json");

    var raw = JSON.stringify({
      username: username,
      password: passWord,
      module: "authentication",
      submodule: "password_reset",
    });

    var requestOptions = {
      method: "POST",
      headers: myHeaders,
      body: raw,
      redirect: "follow",
    };

    fetch(process.env.REACT_APP_BASE_URL, requestOptions)
      .then((response) => response.json())
      .then((result) => {
        setShowbackDrop(false);
        console.log("the result is :", result);
        if (result.status === 400 || result.status === 500) {
          setSnackbar({
            type: "error",
            content: result.message,
            show: true,
          });
        } else {
          setSnackbar({
            type: "success",
            content: "অভিনন্দন ! আপনার পাসওয়ার্ড পরিবর্তিত হয়েছে ",
            show: true,
          });
          setOpen(false);
          handleModalClose();
        }
      })
      .catch((error) => {
        setShowbackDrop(false);
        console.log("the error is :", error);
        setSnackbar({
          type: "error",
          content: "SomeThing Went Wrong. Please Try Again",
          show: true,
        });
      });
  };
  return (
    <Dialog
      open={open}
      // onClose={handleClose}
      aria-labelledby="alert-dialog-title"
      aria-describedby="alert-dialog-description"
    >
      <IconButton
        aria-label="close"
        onClick={handleClose}
        sx={{
          position: "absolute",
          right: 8,
          top: 8,
          color: (theme) => theme.palette.grey[500],
        }}
      >
        <CloseIcon />
      </IconButton>
      <DialogContent>
        {currentStage === "sendEmail" ? (
          <Box
            sx={{
              display: "flex",
              flexDirection: "column",
              justifyContent: "center",
              alignItems: "center",
              gap: 2,
              border: "2px solid #EFEFEF",
              m: 2,
              p: 5,
            }}
          >
            <Box
              sx={{
                display: "flex",
                flexDirection: "column",
                justifyContent: "center",
                alignItems: "center",
                border: "0px solid red",
              }}
            >
              <LockIcon fontSize="large" />
              <Typography
                sx={{
                  fontSize: "150%",
                  fontWeight: 500,
                  fontFamily: "Tiro Bangla, serif",
                }}
              >
                পাসওয়ার্ড ভুলে গেছেন?
              </Typography>
              {/* <Typography>You can reset password here</Typography> */}
            </Box>

            <TextField
              InputLabelProps={{ shrink: true }}
              fullWidth
              id="username_textfield"
              margin="normal"
              label="ইমেইল"
              value={username}
              onChange={handleChange}
              name="username"
              size="small"
            />
            <Button
              variant="contained"
              fullWidth
              onClick={(e) => handleEmailSubmit(e)}
              sx={{
                fontFamily: "Tiro Bangla, serif",
                fontSize: "110%",
                backgroundColor: "white",
                color: "black",
                "&:hover": {
                  backgroundColor: "white",
                },
              }}
              type="submit"
            >
              জমা দিন
            </Button>
          </Box>
        ) : currentStage === "sendOTP" ? (
          <Box
            sx={{
              display: "flex",
              flexDirection: "column",
              justifyContent: "center",
              alignItems: "center",
              gap: 2,
              border: "0px solid red",
              m: 5,
            }}
          >
            <Typography
              sx={{
                textAlign: "center",
                fontSize: "1.2rem",
                fontWeight: 600,
                fontFamily: "Tiro Bangla, serif",
              }}
            >
              আপনার ইমেইলে একটি গোপন কোড পাঠানো হয়েছে, সেই গোপন কোডটি এখানে
              লিখুন
            </Typography>
            <TextField
              required
              fullWidth
              label="OTP"
              id="confirmPassword"
              autoComplete="new-password"
              value={OTP}
              onChange={handleOTPInput}
            />
            <Button
              fullWidth
              variant="contained"
              onClick={handleOTPSubmit}
              sx={{
                fontFamily: "Tiro Bangla, serif",
                fontSize: "110%",
                backgroundColor: "white",
                color: "black",
                "&:hover": {
                  backgroundColor: "white",
                },
              }}
            >
              জমা দিন
            </Button>
          </Box>
        ) : currentStage === "resetpassword" ? (
          <Box
            sx={{
              display: "flex",
              flexDirection: "column",
              justifyContent: "center",
              alignItems: "center",
              gap: 2,
              border: "0px solid red",
              m: 5,
            }}
          >
            <Typography
              sx={{
                fontSize: "150%",
                fontWeight: 500,
                fontFamily: "Tiro Bangla, serif",
              }}
            >
              পাসওয়ার্ড পরিবর্তন করুন
            </Typography>
            <TextField
              InputLabelProps={{ shrink: true }}
              fullWidth
              margin="normal"
              id="password"
              type="password"
              label="পাসওয়ার্ড"
              value={passWord}
              onChange={handlePassWordChange}
              name="password"
              size="small"
            />
            <TextField
              InputLabelProps={{ shrink: true }}
              fullWidth
              // margin="normal"
              id="confirm_password"
              type="password"
              label="পাসওয়ার্ড নিশ্চিত করুন"
              value={confirmPassword}
              onChange={hadleConfirmPassWordChange}
              name="confirm_password"
              size="small"
            />
            {showResetButton ? (
              <Button
                fullWidth
                variant="contained"
                onClick={handlePassResetSubmit}
                sx={{
                  fontFamily: "Tiro Bangla, serif",
                  fontSize: "110%",
                  backgroundColor: "white",
                  color: "black",
                  "&:hover": {
                    backgroundColor: "white",
                  },
                }}
              >
                জমা দিন
              </Button>
            ) : null}
          </Box>
        ) : null}
      </DialogContent>
      {showbackDrop ? (
        <Backdrop
          sx={{ color: "#fff", zIndex: (theme) => theme.zIndex.drawer + 1 }}
          open={open}
          onClick={handleClose}
        >
          <CircularProgress color="inherit" />
        </Backdrop>
      ) : null}
    </Dialog>
  );
}

export default ResetPasswordOTP;
