import { Box, Typography } from "@mui/material";
import Backdrop from "@mui/material/Backdrop";
import Button from "@mui/material/Button";
import CircularProgress from "@mui/material/CircularProgress";
import TextField from "@mui/material/TextField";
import React, { useEffect, useState } from "react";
import shruti_logo from "../../images/Shruti_logo.png";
// import {
//   LoadCanvasTemplate,
//   loadCaptchaEnginge,
//   validateCaptcha,
// } from "react-simple-captcha";
import OTPModal from "./OTPModal";

function NewSignUp({ setShow, show, setUserName, setSnackbar }) {
  const [userInfo, setUserInfo] = useState({
    username: "",
    password: "",
    confirm_password: "",
  });
  const [showbackDrop, setShowbackDrop] = useState(false);
  const [showOTPModal, setShowOTPModal] = useState(false);
  const [open, setOpen] = useState(true);

  useEffect(() => {
    // loadCaptchaEnginge(6, "black", "white");
  }, []);
  const handleChange = (e) => {
    setUserInfo((prevState) => ({
      ...prevState,
      [e.target.name]: e.target.value,
    }));
  };
  const handleClose = () => {
    setOpen(false);
  };
  const handleSubmit = async () => {
    if (doSubmit()) {
      const password = userInfo["password"];
      const confirmPassword = userInfo["confirm_password"];

      if (password !== confirmPassword) {
        setSnackbar({
          type: "error",
          content: "Passwords do not match.",
          show: true,
        });
      } else if (
        password !== "" &&
        confirmPassword !== "" &&
        userInfo["username"] !== ""
      ) {
        setShowbackDrop(true);
        var myHeaders = new Headers();
        myHeaders.append("Content-Type", "application/json");

        var raw = JSON.stringify({
          username: userInfo["username"],
          module: "authentication",
          submodule: "send_mail",
        });

        var requestOptions = {
          method: "POST",
          headers: myHeaders,
          body: raw,
          redirect: "follow",
        };

        fetch(process.env.REACT_APP_BASE_URL, requestOptions)
          .then((response) => response.json())
          .then((result) => {
            setShowbackDrop(false);
            if (result.status === 400) {
              setSnackbar({
                type: "error",
                content: result.message,
                show: true,
              });
            } else {
              setUserInfo({
                username: userInfo["username"],
                password: userInfo["password"],
              });
              setShowOTPModal(true);
            }
            // console.log("signUp result is  :", result);
          })
          .catch((error) => {
            // console.log("error", error);
            setShowbackDrop(false);
          });
      } else {
        setSnackbar({
          type: "error",
          content: "ইমেইল অথবা পাসওয়ার্ড ঘরটি খালি আছে",
          show: true,
        });
      }

      return;
    }
  };
  const doSubmit = () => {
    return true;
    // let user_captcha = document.getElementById("user_captcha_input").value;

    // if (validateCaptcha(user_captcha) === true) {
    //   loadCaptchaEnginge(6, "black", "white");
    //   document.getElementById("user_captcha_input").value = "";
    //   return true;
    // } else {
    //   document.getElementById("user_captcha_input").value = "";
    //   setSnackbar({
    //     type: "error",
    //     content: "Captcha did not match.",
    //     show: true,
    //   });
    //   return false;
    // }
  };
  return (
    <Box
      sx={{
        display: "flex",
        flexDirection: "column",
        // gap: 2,
        justifyContent: "center",
        alignItems: "center",
        border: "0px solid red",
        // mx: "auto",
        height: "100%",
        width: "100%",
        overflowY: "auto",
      }}
    >
      <Box
        sx={{
          display: "flex",
          // flexDirection: "column",
          // gap: 2,
          justifyContent: "center",
          alignItems: "center",
          border: "0px solid red",
          // mx: "auto",
          height: "25%",
          width: "100%",
          overflowY: "auto",
        }}
      >
        <Box
          sx={{
            height: "50%",
            border: "0px solid green",
            width: "100%",
            display: "flex",
            justifyContent: "center",
            alignItems: "center",
            flexDirection: "column",
            // gap: 2,
          }}
        >
          <img
            src={shruti_logo}
            alt="main_logo"
            style={{ height: "75%", width: "auto" }}
          />
          <Typography
            sx={{
              fontFamily: "'Noto Serif Bengali', serif",
              fontSize: { xs: "175%", sm: "175%", md: "150%", lg: "150%" },
              fontWeight: "bold",
              color: "#808285",
            }}
          >
            উচ্চারণ
          </Typography>
        </Box>
      </Box>

      <Box
        sx={{
          display: "flex",
          flexDirection: "column",
          // gap: 2,
          justifyContent: "center",
          alignItems: "center",
          border: "0px solid red",
          // mx: "auto",
          height: "75%",
          width: "100%",
          overflowY: "auto",
        }}
      >
        <Box
          sx={{
            height: "10%",
            border: "0px solid green",
            width: "100%",
            display: "flex",
            justifyContent: "center",
            alignItems: "center",
          }}
        >
          <span
            style={{
              fontSize: "150%",
              // fontWeight: "bold",
              fontFamily: "'Noto Serif Bengali', serif",
            }}
          >
            নিবন্ধন করুন
          </span>
        </Box>
        <Box
          sx={{
            height: "90%",
            border: "0px solid orange",
            width: "80%",
          }}
        >
          <TextField
            fullWidth
            id="username_textfield"
            margin="normal"
            label="ইমেইল"
            value={userInfo.username}
            onChange={handleChange}
            name="username"
            size="small"
            InputLabelProps={{
              sx: {
                fontFamily: "'Noto Serif Bengali', serif",
                fontWeight: "bold",
                fontSize: "19px",
                color: "#949599",
              },
              shrink: true,
            }}
          />
          <TextField
            fullWidth
            margin="normal"
            id="password"
            type="password"
            label="পাসওয়ার্ড"
            value={userInfo.password}
            onChange={handleChange}
            name="password"
            size="small"
            InputLabelProps={{
              sx: {
                fontFamily: "'Noto Serif Bengali', serif",
                fontWeight: "bold",
                fontSize: "18px",
                color: "#949599",
              },
              shrink: true,
            }}
          />
          <TextField
            fullWidth
            margin="normal"
            id="confirm_password"
            type="password"
            label="পাসওয়ার্ড নিশ্চিত করুন"
            value={userInfo.confirm_password}
            onChange={handleChange}
            name="confirm_password"
            size="small"
            InputLabelProps={{
              sx: {
                fontFamily: "'Noto Serif Bengali', serif",
                fontWeight: "bold",
                fontSize: "18.5px",
                color: "#949599",
              },
              shrink: true,
            }}
          />
          {/* <Box
          sx={{
            border: "0px solid #EFEFEF",
            display: "flex",
            justifyContent: "center",
            flexDirection: "column",
            borderRadius: "5px",
          }}
        >
          <LoadCanvasTemplate reloadColor="red" reloadText="Reload" />
          <TextField
            margin="normal"
            id="user_captcha_input"
            label="Captcha"
            size="small"
          />
        </Box> */}
          <Box
            sx={{
              display: "flex",
              flexDirection: "row",
              justifyContent: "space-between",
              paddingTop: "20px",
            }}
          >
            <Button
              color="error"
              variant="transparent"
              fullWidth
              onClick={() => setShow("sign-in")}
              sx={{
                width: "40%",
                border: "1px solid #cccccc",
                "&:hover": {
                  backgroundColor: "inherit", // You can set this to 'none' or any other value to remove the hover effect
                },
                fontFamily: "'Noto Serif Bengali', serif",
                fontWeight: "bold",
                color: "#666666",
              }}
            >
              লগইন
            </Button>
            <Button
              color="success"
              variant="transparent"
              fullWidth
              onClick={() => handleSubmit()}
              sx={{
                width: "40%",
                border: "1px solid #cccccc",
                "&:hover": {
                  backgroundColor: "inherit", // You can set this to 'none' or any other value to remove the hover effect
                },
                fontFamily: "'Noto Serif Bengali', serif",
                fontWeight: "bold",
                color: "#666666",
              }}
            >
              রেজিস্টার
            </Button>
          </Box>
        </Box>
      </Box>
      {showbackDrop ? (
        <Backdrop
          sx={{ color: "#fff", zIndex: (theme) => theme.zIndex.drawer + 1 }}
          open={open}
          onClick={handleClose}
        >
          <CircularProgress color="inherit" />
        </Backdrop>
      ) : null}

      {showOTPModal ? (
        <OTPModal
          setShowOTPModal={setShowOTPModal}
          userInfo={userInfo}
          setSnackbar={setSnackbar}
          setShow={setShow}
        />
      ) : null}
    </Box>
  );
}

export default NewSignUp;
